const b = $input.first().json.body || $input.first().json;
const q = $input.first().json.query || {};

// Custom forms already use the standard shape — just normalize variations
const property = [
  b.property_address,
  b.street_address ? `${b.street_address}, ${b.city || ''}, ${b.state || 'MN'} ${b.zip || ''}`.trim() : null
].find(Boolean) || '';

return [{
  json: {
    client_token: q.token || b.client_token || '',
    lead_name: b.lead_name || b.name || b.contact_name || '',
    email: b.email || b.lead_email || '',
    phone: b.phone || b.lead_phone || '',
    source: b.source || 'custom_form',
    property_address: property,
    price_range: b.price_range || '',
    beds: b.beds || null,
    lead_message: b.lead_message || b.message || b.notes || ''
  }
}];
